1	const PROCESSING_FEE = 5;
2	const COMPONENT_PREMIUM = 25;
3	const BLOCK_SIZE = 3;
4	const BLOCK_PREMIUM = 60;
5	const DEDUCTIBLE = 100;
6	
7	const INSURANCE_VALUES: Record<string, number> = {
8	  sword: 1000,
9	  amulet: 600,
10	  staff: 800,
11	  potion: 400,
12	};
13	const COMPONENT_INSURANCE_VALUE = 250;
14	
15	const MAIN_ITEM_PREMIUMS: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	
22	const isComponent = (item: any): boolean => !(item.type in MAIN_ITEM_PREMIUMS);
23	
24	const countComponentsByType = (items: any[]): Record<string, number> => {
25	  const counts: Record<string, number> = {};
26	  for (const item of items) {
27	    if (isComponent(item)) {
28	      counts[item.type] = (counts[item.type] ?? 0) + 1;
29	    }
30	  }
31	  return counts;
32	};
33	
34	const calculateComponentPremium = (count: number): number =>
35	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * COMPONENT_PREMIUM;
36	
37	const calculateMainItemPremium = (item: any): number => {
38	  const base = MAIN_ITEM_PREMIUMS[item.type] ?? 0;
39	  const curseSurcharge = item.cursed ? base * 0.5 : 0;
40	  const enchantmentSurcharge = item.enchantment >= 5 ? base * 0.3 : 0;
41	  return base + curseSurcharge + enchantmentSurcharge;
42	};
43	
44	const calculateQuotePremium = (items: any[], customer: any, isFollowUp: boolean): number => {
45	  const mainItems = items.filter((item: any) => !isComponent(item));
46	
47	  const policyBasePremium = mainItems
48	    .reduce((sum: number, item: any) => sum + (MAIN_ITEM_PREMIUMS[item.type] ?? 0), 0);
49	
50	  const mainItemPremium = mainItems
51	    .reduce((sum: number, item: any) => sum + calculateMainItemPremium(item), 0);
52	
53	  const componentCounts = countComponentsByType(items);
54	  const componentPremium = Object.values(componentCounts)
55	    .reduce((sum: number, count: number) => sum + calculateComponentPremium(count), 0);
56	
57	  const firstInsuranceSurcharge = policyBasePremium * 0.1;
58	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
59	  const followUpDiscount = isFollowUp ? policyBasePremium * 0.15 : 0;
60	
61	  return mainItemPremium + componentPremium + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
62	};
63	
64	const calculateInsuranceSum = (items: any[]): number => {
65	  return items.reduce((sum: number, item: any) => {
66	    if (isComponent(item)) {
67	      return sum + COMPONENT_INSURANCE_VALUE;
68	    }
69	    return sum + (INSURANCE_VALUES[item.type] ?? 0);
70	  }, 0);
71	};
72	
73	const calculateReimbursement = (damage: any, item: any): number => {
74	  const isHighEnchantment = item && item.enchantment >= 8;
75	  return isHighEnchantment ? damage.amount * 0.5 : damage.amount;
76	};
77	
78	const calculateClaimPayout = (damages: any[], policyItems: any[]): number =>
79	  damages.reduce((total: number, damage: any) => {
80	    const item = policyItems.find((i: any) => i.type === damage.itemType);
81	    const reimbursement = calculateReimbursement(damage, item);
82	    return total + Math.max(0, reimbursement - DEDUCTIBLE);
83	  }, 0);
