85	export function processScenario(scenario: any): unknown {
86	  let quoteCount = 0;
87	  const policies: Record<number, { items: any[]; remainingCap: number }> = {};
88	
89	  const results = scenario.steps.map((step: any, index: number) => {
90	    if (step.op === "quote") {
91	      const isFollowUp = quoteCount > 0;
92	      quoteCount++;
93	      const insuranceSum = calculateInsuranceSum(step.items);
94	      policies[index] = { items: step.items, remainingCap: insuranceSum * 2 };
95	      return { premium: calculateQuotePremium(step.items, scenario.customer, isFollowUp) };
96	    }
