16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	  potion: 40,
20	};
21	
22	const isComponent = (item: any): boolean => !(item.type in MAIN_ITEM_PREMIUMS);
23	
24	const countComponentsByType = (items: any[]): Record<string, number> => {
25	  const counts: Record<string, number> = {};
26	  for (const item of items) {
27	    if (isComponent(item)) {
28	      counts[item.type] = (counts[item.type] ?? 0) + 1;
29	    }
30	  }
31	  return counts;
32	};
