44	const calculateQuotePremium = (items: any[], customer: any, isFollowUp: boolean): number => {
45	  const mainItems = items.filter((item: any) => !isComponent(item));
46	
47	  const policyBasePremium = mainItems
48	    .reduce((sum: number, item: any) => sum + (MAIN_ITEM_PREMIUMS[item.type] ?? 0), 0);
49	
50	  const mainItemPremium = mainItems
51	    .reduce((sum: number, item: any) => sum + calculateMainItemPremium(item), 0);
52	
53	  const componentCounts = countComponentsByType(items);
54	  const componentPremium = Object.values(componentCounts)
55	    .reduce((sum: number, count: number) => sum + calculateComponentPremium(count), 0);
56	
57	  const firstInsuranceSurcharge = policyBasePremium * 0.1;
58	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? policyBasePremium * 0.2 : 0;
59	  const followUpDiscount = isFollowUp ? policyBasePremium * 0.15 : 0;
60	
61	  return mainItemPremium + componentPremium + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
62	};
